     1→// Module: Safety — CortexBuild Ultimate
     2→// "HSE Intelligence Hub" Redesign
     3→import { useState, useMemo } from 'react';
     4→import {
     5→  Shield, AlertTriangle, CheckCircle2, AlertCircle, FileText,
     6→  Plus, X, Loader2, Search, Edit2, Trash2, RefreshCw,
     7→  TrendingUp, Activity, MapPin, Calendar, ChevronRight,
     8→  BarChart3, PieChart, Layers, Clock, User
     9→} from 'lucide-react';
    10→import { useSafety, useProjects } from '../../hooks/useData';
    11→import {
    12→  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer,
    13→  BarChart, Bar, Pie, PieChart as RechartsPie, Cell, AreaChart, Area
    14→} from 'recharts';
    15→import type { Module } from '../../types';
    16→
    17→type AnyRow = Record<string, unknown>;
    18→
    19→const severityConfig: Record<string, { label: string; color: string; bg: string }> = {
    20→  low: { label: 'Low', color: 'var(--emerald-400)', bg: 'rgba(16,185,129,0.1)' },
    21→  medium: { label: 'Medium', color: 'var(--amber-400)', bg: 'rgba(245,158,11,0.1)' },
    22→  high: { label: 'High', color: 'var(--orange-400)', bg: 'rgba(251,146,60,0.1)' },
    23→  critical: { label: 'Critical', color: 'var(--red-400)', bg: 'rgba(248,113,113,0.1)' },
    24→};
    25→
    26→const statusConfig: Record<string, { label: string; color: string }> = {
    27→  open: { label: 'Open', color: 'var(--red-400)' },
    28→  investigating: { label: 'Investigating', color: 'var(--amber-400)' },
    29→  closed: { label: 'Closed', color: 'var(--emerald-400)' },
    30→  resolved: { label: 'Resolved', color: 'var(--emerald-400)' },
    31→};
    32→
    33→const typeConfig: Record<string, { label: string; icon: React.FC<{ className?: string }> }> = {
    34→  near_miss: { label: 'Near Miss', icon: AlertTriangle },
    35→  first_aid: { label: 'First Aid', icon: AlertCircle },
    36→  riddor: { label: 'RIDDOR', icon: FileText },
    37→  incident: { label: 'Incident', icon: AlertTriangle },
    38→  hazard: { label: 'Hazard', icon: AlertTriangle },
    39→};
    40→
    41→const COLORS = ['var(--red-400)', 'var(--orange-400)', 'var(--amber-400)', 'var(--emerald-400)'];
    42→const MONTHS = ['Sep','Oct','Nov','Dec','Jan','Feb','Mar'];
    43→
    44→const defaultForm = {
    45→  title: '', type: 'near_miss', severity: 'medium', status: 'open',
    46→  project: '', location: '', date: new Date().toISOString().split('T')[0],
    47→  description: '', immediate_action: '', injured_party: '',
    48→  reported_by_name: '', riddor_reportable: false,
    49→};
    50→type FormData = typeof defaultForm;
    51→
    52→const buildTrendData = (incidents: AnyRow[]) => {
    53→  const data = MONTHS.map(m => ({ month: m, incidents: 0, nearMisses: 0, toolboxTalks: 0 }));
    54→  incidents.forEach(inc => {
    55→    const d = new Date(String(inc.date ?? ''));
    56→    const idx = d.getMonth() - 8;
    57→    if (idx >= 0 && idx < 7) {
    58→      const t = String(inc.type ?? '');
    59→      if (['incident','first_aid','riddor'].includes(t)) data[idx].incidents++;
    60→      else if (['near-miss','near_miss'].includes(t)) data[idx].nearMisses++;
    61→      else if (['toolbox-talk','toolbox_talk'].includes(t)) data[idx].toolboxTalks++;
    62→    }
    63→  });
    64→  return data;
    65→};
    66→
    67→const buildRiskHeatmap = (incidents: AnyRow[], projects: AnyRow[]) => {
    68→  const risk: Record<string, any> = {};
    69→  projects.forEach(p => { risk[String(p.name ?? 'Unknown')] = { name: String(p.name ?? 'Unknown'), critical: 0, high: 0, medium: 0, low: 0, score: 0 }; });
    70→  incidents.forEach(inc => {
    71→    const proj = String(inc.project ?? 'Unknown');
    72→    const sev = String(inc.severity ?? 'low');
    73→    if (!risk[proj]) risk[proj] = { name: proj, critical: 0, high: 0, medium: 0, low: 0, score: 0 };
    74→    risk[proj][sev] = (risk[proj][sev] ?? 0) + 1;
    75→    risk[proj].score += {critical:4,high:3,medium:2,low:1}[sev] ?? 1;
    76→  });
    77→  return Object.values(risk).sort((a,b) => b.score - a.score).slice(0, 5);
    78→};
    79→
    80→const buildRootCauseData = (incidents: AnyRow[]) => {
    81→  const causes: Record<string, number> = {};
    82→  incidents.forEach(inc => { causes[String(inc.root_cause ?? 'unknown')] = (causes[String(inc.root_cause ?? 'unknown')] ?? 0) + 1; });
    83→  return Object.entries(causes).map(([name, value]) => ({ name, value }));
    84→};
    85→
    86→const buildForecastData = (trendData: any[]) => {
    87→  const last = trendData[trendData.length - 1];
    88→  const avgGrowth = trendData.length > 1 ? (last.incidents - trendData[0].incidents) / trendData.length : 0;
    89→  return ['Apr','May','Jun'].map((m, i) => ({
    90→    month: m,
    91→    projected: Math.round(last.incidents + avgGrowth * (i + 1)),
    92→    target: Math.max(0, last.incidents - 2)
    93→  }));
    94→};
    95→
    96→export function Safety({ setModule }: { setModule?: (m: Module) => void }) {
    97→  const { useList, useCreate, useUpdate, useDelete } = useSafety;
    98→  const { data: rawProjects = [] } = useProjects.useList();
    99→  const { data: raw = [], isLoading, refetch } = useList();
   100→  const incidents = raw as AnyRow[];
   101→  const createM = useCreate(); const updateM = useUpdate(); const deleteM = useDelete();
   102→
   103→  const [categoryTab, setCategoryTab] = useState('all');
   104→  const [filter, setFilter] = useState('all');
   105→  const [search, setSearch] = useState('');
   106→  const [showModal, setShowModal] = useState(false);
   107→  const [editId, setEditId] = useState<string | null>(null);
   108→  const [form, setForm] = useState<FormData>(defaultForm);
   109→  const [selectedId, setSelectedId] = useState<string | null>(null);
   110→
   111→  const TYPE_MAP: Record<string, string[]> = {
   112→    all: [], incidents: ['incident','first_aid','riddor'], near_misses: ['near-miss','near_miss'],
   113→    hazards: ['hazard','dangerous_occurrence','environmental'], mewp: ['mewp-check','mewp_check'],
   114→    toolbox: ['toolbox-talk','toolbox_talk'], riddor: ['riddor'],
   115→  };
   116→
   117→  const filtered = incidents
   118→    .filter(i => categoryTab === 'all' || TYPE_MAP[categoryTab]?.includes(String(i.type ?? '')))
   119→    .filter(i => filter === 'all' || i.status === filter || i.severity === filter)
   120→    .filter(i => !search || String(i.title).toLowerCase().includes(search.toLowerCase()));
   121→
   122→  const counts = {
   123→    open: incidents.filter(i => ['open','investigating'].includes(String(i.status ?? ''))).length,
   124→    critical: incidents.filter(i => ['critical','serious'].includes(String(i.severity ?? ''))).length,
   125→    riddor: incidents.filter(i => i.riddor_reportable || String(i.type) === 'riddor').length,
   126→    closed: incidents.filter(i => ['closed','resolved'].includes(String(i.status ?? ''))).length,
   127→    total: incidents.length,
   128→  };
   129→
   130→  const trendData = useMemo(() => buildTrendData(incidents), [incidents]);
   131→  const riskHeatmap = useMemo(() => buildRiskHeatmap(incidents, rawProjects as AnyRow[]), [incidents, rawProjects]);
   132→  const rootCauseData = useMemo(() => buildRootCauseData(incidents), [incidents]);
   133→  const forecastData = useMemo(() => buildForecastData(trendData), [trendData]);
   134→  const safetyScore = incidents.length ? Math.max(0, 100 - counts.open * 8 - counts.critical * 15) : 100;
   135→  const safetyColor = safetyScore >= 80 ? 'var(--emerald-400)' : safetyScore >= 60 ? 'var(--amber-400)' : 'var(--red-400)';
   136→  const selected = incidents.find(i => String(i.id) === selectedId);
   137→
   138→  const openCreate = () => { setForm(defaultForm); setEditId(null); setShowModal(true); };
   139→  const openEdit = (i: AnyRow) => {
   140→    setForm({ ...defaultForm, title: String(i.title??''), type: String(i.type??'near_miss'), severity: String(i.severity??'medium'),
   141→      status: String(i.status??'open'), project: String(i.project??''), location: String(i.location??''),
   142→      date: String(i.date??new Date().toISOString().split('T')[0]), description: String(i.description??''),
   143→      reported_by_name: String(i.reported_by_name??i.reportedBy??''), riddor_reportable: Boolean(i.riddor_reportable) });
   144→    setEditId(String(i.id)); setShowModal(true);
   145→  };
   146→
   147→  const handleSubmit = async (e: React.FormEvent) => { e.preventDefault(); if (editId) await updateM.mutateAsync({ id: editId, data: form }); else await createM.mutateAsync(form); setShowModal(false); };
   148→  const handleDelete = async (id: string) => { if (!confirm('Delete?')) return; await deleteM.mutateAsync(id); setSelectedId(null); };
   149→
   150→  const inp = "w-full bg-slate-800 border border-slate-600 rounded-lg px-4 py-2.5 text-white text-sm focus:outline-none focus:border-amber-500";
   151→  const lbl = "block text-xs font-semibold text-slate-400 mb-1.5 uppercase";
   152→
   153→  return (
   154→    <div className="module-page" style={{ minHeight: '100%', background: 'var(--slate-950)', padding: '24px' }}>
   155→      {/* Header */}
   156→      <div className="card animate-fade-up" style={{ padding: '24px 28px', marginBottom: '20px', background: 'linear-gradient(135deg, rgba(13,17,23,0.95), rgba(8,11,18,0.9))', border: '1px solid var(--slate-700)', position: 'relative', overflow: 'hidden' }}>
   157→        <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none', opacity: 0.05, backgroundImage: 'linear-gradient(rgba(248,113,113,0.3) 1px, transparent 1px), linear-gradient(90deg, rgba(248,113,113,0.3) 1px, transparent 1px)', backgroundSize: '32px 32px' }} />
   158→        <div style={{ display: 'grid', gridTemplateColumns: '1fr auto 1fr', alignItems: 'center', gap: '24px', position: 'relative', zIndex: 1 }}>
   159→          <div>
   160→            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '6px' }}>
   161→              <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', fontWeight: 800, color: 'var(--slate-50)', letterSpacing: '-0.03em' }}>HSE Intelligence Hub</span>
   162→              <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: safetyColor, boxShadow: '0 0 8px currentColor', animation: 'pulse 2s ease-in-out infinite' }} />
   163→            </div>
   164→            <p style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--slate-500)', letterSpacing: '0.08em' }}>
   165→              REAL-TIME RISK INTELLIGENCE · RIDDOR COMPLIANCE
   166→            </p>
   167→          </div>
   168→          <div style={{ display: 'flex', gap: '12px' }}>
   169→            <div style={{ textAlign: 'center', padding: '12px 20px', background: 'rgba(245,158,11,0.1)', border: '1px solid rgba(245,158,11,0.3)', borderRadius: '12px' }}>
   170→              <div style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--amber-400)', marginBottom: '4px' }}>SAFETY SCORE</div>
   171→              <div style={{ fontFamily: 'var(--font-display)', fontSize: '28px', fontWeight: 800, color: safetyColor }}>{safetyScore}</div>
   172→            </div>
   173→          </div>
   174→          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '10px' }}>
   175→            <button onClick={openCreate} style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 18px', background: 'var(--amber-500)', border: 'none', borderRadius: '8px', color: 'var(--slate-950)', fontFamily: 'var(--font-body)', fontSize: '13px', fontWeight: 600, cursor: 'pointer' }}>
   176→              <Plus style={{ width: '16px', height: '16px' }} /> Report Incident
   177→            </button>
   178→            <button onClick={() => refetch()} style={{ padding: '10px 14px', background: 'var(--slate-800)', border: '1px solid var(--slate-700)', borderRadius: '8px', color: 'var(--slate-400)', cursor: 'pointer', transition: 'all 0.2s' }} onMouseEnter={e => { e.currentTarget.style.background = 'var(--slate-700)'; e.currentTarget.style.color = 'var(--slate-100)'; }} onMouseLeave={e => { e.currentTarget.style.background = 'var(--slate-800)'; e.currentTarget.style.color = 'var(--slate-400)'; }}>
   179→              <RefreshCw style={{ width: '16px', height: '16px' }} />
   180→            </button>
   181→          </div>
   182→        </div>
   183→      </div>
   184→
   185→      {/* KPI Grid */}
   186→      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '16px', marginBottom: '24px' }}>
   187→        {[
   188→          { label: 'Total Incidents', value: counts.total, color: 'var(--slate-400)', icon: Activity },
   189→          { label: 'Open', value: counts.open, color: 'var(--red-400)', icon: AlertCircle },
   190→          { label: 'Critical', value: counts.critical, color: 'var(--orange-400)', icon: AlertTriangle },
   191→          { label: 'RIDDOR', value: counts.riddor, color: 'var(--amber-400)', icon: FileText },
   192→          { label: 'Closed', value: counts.closed, color: 'var(--emerald-400)', icon: CheckCircle2 },
   193→        ].map((kpi, i) => {
   194→          const Icon = kpi.icon;
   195→          return (
   196→            <div key={i} className="card animate-fade-up" style={{ padding: '18px 20px', background: 'var(--slate-900)', border: '1px solid var(--slate-800)', animationDelay: `${i * 0.05}s` }}>
   197→              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
   198→                <div style={{ width: '40px', height: '40px', borderRadius: '8px', background: `${kpi.color}15`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
   199→                  <Icon style={{ width: '20px', height: '20px', color: kpi.color }} />
   200→                </div>
   201→                <div>
   202→                  <div style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: kpi.color, textTransform: 'uppercase', letterSpacing: '0.08em' }}>{kpi.label}</div>
   203→                  <div style={{ fontFamily: 'var(--font-display)', fontSize: '24px', fontWeight: 800, color: 'var(--slate-50)' }}>{kpi.value}</div>
   204→                </div>
   205→              </div>
   206→            </div>
   207→          );
   208→        })}
   209→      </div>
   210→
   211→      {/* Main Charts Grid */}
   212→      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '24px' }}>
   213→        {/* Trend Chart */}
   214→        <div className="card" style={{ padding: '20px', background: 'var(--slate-900)', border: '1px solid var(--slate-800)' }}>
   215→          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '16px' }}>
   216→            <TrendingUp style={{ width: '18px', height: '18px', color: 'var(--amber-400)' }} />
   217→            <span style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-50)' }}>Incident Trends</span>
   218→          </div>
   219→          <div style={{ height: '220px' }}>
   220→            <ResponsiveContainer width="100%" height="100%">
   221→              <AreaChart data={trendData}>
   222→                <defs>
   223→                  <linearGradient id="gradInc" x1="0" y1="0" x2="0" y2="1">
   224→                    <stop offset="5%" stopColor="var(--red-400)" stopOpacity={0.3}/>
   225→                    <stop offset="95%" stopColor="var(--red-400)" stopOpacity={0}/>
   226→                  </linearGradient>
   227→                  <linearGradient id="gradNear" x1="0" y1="0" x2="0" y2="1">
   228→                    <stop offset="5%" stopColor="var(--amber-400)" stopOpacity={0.3}/>
   229→                    <stop offset="95%" stopColor="var(--amber-400)" stopOpacity={0}/>
   230→                  </linearGradient>
   231→                </defs>
   232→                <CartesianGrid strokeDasharray="3 3" stroke="var(--slate-800)" />
   233→                <XAxis dataKey="month" stroke="var(--slate-600)" fontSize={11} />
   234→                <YAxis stroke="var(--slate-600)" fontSize={11} />
   235→                <RechartsTooltip contentStyle={{ background: 'var(--slate-900)', border: '1px solid var(--slate-700)', fontFamily: 'var(--font-body)' }} />
   236→                <Legend wrapperStyle={{ fontFamily: 'var(--font-body)', fontSize: '11px' }} />
   237→                <Area type="monotone" dataKey="incidents" stroke="var(--red-400)" fill="url(#gradInc)" strokeWidth={2} name="Incidents" />
   238→                <Area type="monotone" dataKey="nearMisses" stroke="var(--amber-400)" fill="url(#gradNear)" strokeWidth={2} name="Near Misses" />
   239→              </AreaChart>
   240→            </ResponsiveContainer>
   241→          </div>
   242→        </div>
   243→
   244→        {/* Risk Heatmap */}
   245→        <div className="card" style={{ padding: '20px', background: 'var(--slate-900)', border: '1px solid var(--slate-800)' }}>
   246→          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '16px' }}>
   247→            <Layers style={{ width: '18px', height: '18px', color: 'var(--red-400)' }} />
   248→            <span style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-50)' }}>Risk by Project</span>
   249→          </div>
   250→          <div style={{ height: '220px' }}>
   251→            <ResponsiveContainer width="100%" height="100%">
   252→              <BarChart data={riskHeatmap} layout="vertical" barSize={20}>
   253→                <CartesianGrid strokeDasharray="3 3" stroke="var(--slate-800)" />
   254→                <XAxis type="number" stroke="var(--slate-600)" fontSize={11} />
   255→                <YAxis dataKey="name" type="category" stroke="var(--slate-400)" fontSize={11} width={100} />
   256→                <RechartsTooltip contentStyle={{ background: 'var(--slate-900)', border: '1px solid var(--slate-700)', fontFamily: 'var(--font-body)' }} />
   257→                <Legend wrapperStyle={{ fontFamily: 'var(--font-body)', fontSize: '11px' }} />
   258→                <Bar dataKey="critical" stackId="stack" fill="var(--red-400)" name="Critical" />
   259→                <Bar dataKey="high" stackId="stack" fill="var(--orange-400)" name="High" />
   260→                <Bar dataKey="medium" stackId="stack" fill="var(--amber-400)" name="Medium" />
   261→                <Bar dataKey="low" stackId="stack" fill="var(--emerald-400)" name="Low" />
   262→              </BarChart>
   263→            </ResponsiveContainer>
   264→          </div>
   265→        </div>
   266→      </div>
   267→
   268→      {/* Secondary Charts Row */}
   269→      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '24px' }}>
   270→        {/* Root Cause Pie */}
   271→        <div className="card" style={{ padding: '20px', background: 'var(--slate-900)', border: '1px solid var(--slate-800)' }}>
   272→          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '16px' }}>
   273→            <PieChart style={{ width: '18px', height: '18px', color: 'var(--amber-400)' }} />
   274→            <span style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-50)' }}>Root Cause Analysis</span>
   275→          </div>
   276→          <div style={{ height: '220px' }}>
   277→            <ResponsiveContainer width="100%" height="100%">
   278→              <RechartsPie>
   279→                <Pie data={rootCauseData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={80} label>
   280→                  {rootCauseData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
   281→                </Pie>
   282→                <RechartsTooltip contentStyle={{ background: 'var(--slate-900)', border: '1px solid var(--slate-700)', fontFamily: 'var(--font-body)' }} />
   283→                <Legend wrapperStyle={{ fontFamily: 'var(--font-body)', fontSize: '11px' }} />
   284→              </RechartsPie>
   285→            </ResponsiveContainer>
   286→          </div>
   287→        </div>
   288→
   289→        {/* Risk Forecast */}
   290→        <div className="card" style={{ padding: '20px', background: 'var(--slate-900)', border: '1px solid var(--slate-800)' }}>
   291→          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '16px' }}>
   292→            <BarChart3 style={{ width: '18px', height: '18px', color: 'var(--emerald-400)' }} />
   293→            <span style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-50)' }}>Risk Forecast</span>
   294→          </div>
   295→          <div style={{ height: '220px' }}>
   296→            <ResponsiveContainer width="100%" height="100%">
   297→              <LineChart data={forecastData}>
   298→                <CartesianGrid strokeDasharray="3 3" stroke="var(--slate-800)" />
   299→                <XAxis dataKey="month" stroke="var(--slate-600)" fontSize={11} />
   300→                <YAxis stroke="var(--slate-600)" fontSize={11} />
   301→                <RechartsTooltip contentStyle={{ background: 'var(--slate-900)', border: '1px solid var(--slate-700)', fontFamily: 'var(--font-body)' }} />
   302→                <Legend wrapperStyle={{ fontFamily: 'var(--font-body)', fontSize: '11px' }} />
   303→                <Line type="monotone" dataKey="projected" stroke="var(--red-400)" strokeWidth={2} name="Projected" />
   304→                <Line type="monotone" dataKey="target" stroke="var(--emerald-400)" strokeWidth={2} strokeDasharray="4 4" name="Target" />
   305→              </LineChart>
   306→            </ResponsiveContainer>
   307→          </div>
   308→        </div>
   309→      </div>
   310→
   311→      {/* Category Tabs */}
   312→      <div style={{ display: 'flex', gap: '8px', marginBottom: '16px', borderBottom: '1px solid var(--slate-800)', paddingBottom: '12px' }}>
   313→        {['all', 'incidents', 'near_misses', 'hazards', 'toolbox', 'riddor'].map(tab => (
   314→          <button
   315→            key={tab}
   316→            onClick={() => setCategoryTab(tab)}
   317→            style={{
   318→              padding: '8px 16px',
   319→              background: categoryTab === tab ? 'var(--amber-500)' : 'transparent',
   320→              border: 'none',
   321→              borderRadius: '8px',
   322→              color: categoryTab === tab ? 'var(--slate-950)' : 'var(--slate-400)',
   323→              fontFamily: 'var(--font-body)',
   324→              fontSize: '13px',
   325→              fontWeight: 600,
   326→              cursor: 'pointer',
   327→              transition: 'all 0.2s',
   328→              textTransform: 'capitalize',
   329→            }}
   330→            onMouseEnter={e => { if (categoryTab !== tab) { e.currentTarget.style.background = 'rgba(245,158,11,0.1)'; e.currentTarget.style.color = 'var(--amber-400)'; } }}
