    37→// Build monthly chart data from invoices
    38→function buildChartData(invoices: AnyRow[]) {
    39→  const now = new Date();
    40→  const months: { month: string; revenue: number; profit: number }[] = [];
    41→  for (let i = 5; i >= 0; i--) {
    42→    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    43→    months.push({ month: MONTH_ABBR[d.getMonth()], revenue: 0, profit: 0 });
    44→  }
    45→  invoices.filter(inv => inv.status === 'paid').forEach(inv => {
    46→    const dateStr = String(inv.issueDate ?? inv.issue_date ?? '');
    47→    if (!dateStr) return;
    48→    const d = new Date(dateStr);
    49→    const mIdx = months.findIndex(m => m.month === MONTH_ABBR[d.getMonth()] && d.getFullYear() === new Date().getFullYear());
    50→    if (mIdx !== -1) {
    51→      months[mIdx].revenue += Number(inv.amount ?? 0);
    52→      months[mIdx].profit  += Number(inv.amount ?? 0) * 0.23;
    53→    }
    54→  });
    55→  return months;
    56→}
